/usr/bin/bash -lc "python - <<'PY'
import csv
# show active questions updated long ago with Jan4 title keywords for a quick sanity pass
terms=['grok','greenland','fury','manchester united','yemen','crans','venezuela','afcon','cameroon','morocco','immigration','minnesota','gaza']
for r in csv.DictReader(open('market.csv')):
    if r['is_resolved']=='False':
        t=(r['title']+' '+r['background']+' '+r['my_prediction']).lower()
        if any(term in t for term in terms):
            print(r['qid'], r['my_prediction_date'], '|', r['title'][:150], '| pred', r['my_prediction'][:160])
PY"

